    41→	createCmd.Flags().StringVar(&sandboxImage, "image", "ghcr.io/thieso2/sandcastle-sandbox:latest", "Container image")
    42→	createCmd.Flags().BoolVar(&sandboxPersistent, "persistent", false, "Enable persistent volume")
    43→	createCmd.Flags().StringVar(&sandboxSnapshot, "snapshot", "", "Create from snapshot (legacy alias for --from-snapshot)")
    44→	createCmd.Flags().StringVar(&sandboxFromSnapshot, "from-snapshot", "", "Create from snapshot name (restores all available layers)")
    45→	createCmd.Flags().StringVar(&sandboxRestoreLayers, "restore-layers", "", "Comma-separated layers to restore: container,home,data (default: all)")
    46→	createCmd.Flags().BoolVar(&sandboxTailscale, "tailscale", false, "Connect to Tailscale network")
    47→	createCmd.Flags().BoolVarP(&sandboxNoConnect, "no-connect", "n", false, "Don't connect after creation")
    48→	createCmd.Flags().BoolVar(&sandboxRemove, "rm", false, "Delete sandbox on exit (env: SANDCASTLE_RM)")
    49→	createCmd.Flags().BoolVar(&sandboxHome, "home", false, "Mount persistent home directory (env: SANDCASTLE_HOME)")
    50→	createCmd.Flags().StringVar(&sandboxData, "data", "", "Mount user data directory (or subpath) to /data (env: SANDCASTLE_DATA)")
    51→	createCmd.Flags().Lookup("data").NoOptDefVal = "."
    52→	createCmd.Flags().BoolVar(&sandboxNoVNC, "no-vnc", false, "Disable VNC display server")
    53→	createCmd.Flags().StringVar(&sandboxVNCGeometry, "vnc-geometry", "", "VNC screen resolution (e.g. 1920x1080)")
    54→	createCmd.Flags().IntVar(&sandboxVNCDepth, "vnc-depth", 0, "VNC color depth: 8, 16, 24, or 32")
    55→}
    56→
    57→var createCmd = &cobra.Command{
    58→	Use:   "create [name]",
    59→	Short: "Create a new sandbox",
    60→	Long: `Create a new sandbox.
    61→
    62→If no name is provided, creates a temporary sandbox with an auto-generated name like "temp-<timestamp>".
    63→
    64→Environment variables can set defaults for commonly used flags:
    65→  SANDCASTLE_HOME=1    equivalent to --home
    66→  SANDCASTLE_DATA=.    equivalent to --data (value is the subpath, "." or "1" for root)
    67→  SANDCASTLE_RM=1      equivalent to --rm
    68→
    69→Flags explicitly passed on the command line take precedence over environment variables.`,
    70→	Args: cobra.MaximumNArgs(1),
    71→	PreRun: func(cmd *cobra.Command, args []string) {
    72→		if !cmd.Flags().Changed("home") && envTruthy("SANDCASTLE_HOME") {
    73→			sandboxHome = true
    74→		}
    75→		if !cmd.Flags().Changed("rm") && envTruthy("SANDCASTLE_RM") {
    76→			sandboxRemove = true
    77→		}
    78→		if !cmd.Flags().Changed("data") {
    79→			if v := os.Getenv("SANDCASTLE_DATA"); v != "" {
    80→				if v == "1" || v == "true" {
    81→					v = "."
    82→				}
    83→				sandboxData = v
    84→			}
    85→		}
    86→	},
    87→	RunE: func(cmd *cobra.Command, args []string) error {
    88→		client, err := api.NewClient()
    89→		if err != nil {
    90→			return err
    91→		}
    92→		printServer(client)
    93→
    94→		// Auto-generate name if not provided
    95→		var name string
    96→		autoGenerated := false
    97→		if len(args) == 0 {
    98→			name = fmt.Sprintf("temp-%d", time.Now().Unix())
    99→			autoGenerated = true
   100→			// Auto-generated sandboxes are temporary by default
   101→			if !cmd.Flags().Changed("rm") {
   102→				sandboxRemove = true
   103→			}
   104→		} else {
   105→			name = args[0]
   106→		}
   107→
   108→		// Resolve snapshot flags: --from-snapshot takes precedence over --snapshot
   109→		fromSnap := sandboxFromSnapshot
   110→		if fromSnap == "" {
   111→			fromSnap = sandboxSnapshot
   112→		}
   113→
   114→		var restoreLayers []string
   115→		if sandboxRestoreLayers != "" {
   116→			for _, l := range strings.Split(sandboxRestoreLayers, ",") {
   117→				restoreLayers = append(restoreLayers, strings.TrimSpace(l))
   118→			}
   119→		}
   120→
   121→		sandbox, err := client.CreateSandbox(api.CreateSandboxRequest{
   122→			Name:          name,
   123→			Image:         sandboxImage,
   124→			Persistent:    sandboxPersistent,
   125→			FromSnapshot:  fromSnap,
   126→			RestoreLayers: restoreLayers,
   127→			Tailscale:     sandboxTailscale,
   128→			MountHome:     sandboxHome,
   129→			DataPath:      sandboxData,
   130→			Temporary:     sandboxRemove,
   131→			VNCEnabled:    !sandboxNoVNC,
   132→			VNCGeometry:   sandboxVNCGeometry,
   133→			VNCDepth:      sandboxVNCDepth,
   134→		})
   135→		if err != nil {
   136→			return err
   137→		}
   138→
   139→		if autoGenerated {
   140→			fmt.Printf("Sandbox %q created (auto-generated name).\n", sandbox.Name)
   141→		} else {
   142→			fmt.Printf("Sandbox %q created.\n", sandbox.Name)
   143→		}
   144→
   145→		// Print active options (use local flags — they reflect what was actually requested)
   146→		if sandboxHome || sandboxData != "" || sandboxPersistent || sandbox.Tailscale || sandboxRemove || fromSnap != "" || sandboxNoVNC || sandboxVNCGeometry != "" || sandboxVNCDepth != 0 {
   147→			if sandboxHome {
   148→				fmt.Println("  Home:      mounted (~/ persisted)")
   149→			}
   150→			if sandboxData != "" {
   151→				label := sandboxData
   152→				if label == "." {
   153→					label = "user data root"
   154→				}
   155→				fmt.Printf("  Data:      mounted (%s → /data)\n", label)
   156→			}
   157→			if sandboxPersistent {
   158→				fmt.Println("  Volume:    persistent (/workspace)")
   159→			}
   160→			if sandbox.Tailscale {
   161→				fmt.Println("  Tailscale: enabled")
   162→			}
   163→			if sandboxRemove {
   164→				fmt.Println("  Cleanup:   auto-remove on exit")
   165→			}
   166→			if fromSnap != "" {
   167→				fmt.Printf("  Snapshot:  restored from %q\n", fromSnap)
   168→			}
   169→			if sandboxNoVNC {
   170→				fmt.Println("  VNC:       disabled")
   171→			} else if sandboxVNCGeometry != "" || sandboxVNCDepth != 0 {
   172→				geom := sandbox.VNCGeometry
   173→				if geom == "" {
   174→					geom = "1280x900"
   175→				}
   176→				depth := sandbox.VNCDepth
   177→				if depth == 0 {
   178→					depth = 24
   179→				}
   180→				fmt.Printf("  VNC:       %s @ %d-bit\n", geom, depth)
   181→			}
   182→		}
   183→
   184→		if sandboxNoConnect {
   185→			return nil
   186→		}
   187→
   188→		info, err := client.ConnectInfo(sandbox.ID)
   189→		if err != nil {
   190→			return err
   191→		}
   192→
   193→		if os.Getenv("VERBOSE") == "1" {
   194→			fmt.Fprintf(os.Stderr, "\033[2m[verbose] Connection info: host=%s port=%d user=%s\033[0m\n", info.Host, info.Port, info.User)
   195→			if info.TailscaleIP != "" {
   196→				fmt.Fprintf(os.Stderr, "\033[2m[verbose] Tailscale IP (Tailscale): %s\033[0m\n", info.TailscaleIP)
   197→			}
   198→		}
   199→
   200→		if err := waitForSSH(info.Host, info.Port); err != nil {
   201→			return err
   202→		}
   203→
   204→		cfg, loadErr := config.Load()
   205→		if loadErr != nil {
   206→			return loadErr
   207→		}
   208→		prefs := cfg.LoadPreferences()
   209→
   210→		var remoteCmd string
   211→		if *prefs.UseTmux {
   212→			remoteCmd = "tmux new-session -A -s main"
   213→		}
   214→
   215→		var sshErr error
   216→		if prefs.ConnectProtocol == "mosh" {
   217→			sshErr = moshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs)
   218→		} else {
   219→			sshErr = sshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs)
   220→		}
   221→
   222→		if sandboxRemove {
   223→			// Re-fetch to check if user toggled to "keep" during the session
   224→			current, fetchErr := client.GetSandbox(sandbox.ID)
   225→			if fetchErr == nil && !current.Temporary {
   226→				fmt.Printf("Sandbox %q was set to keep — skipping removal.\n", sandbox.Name)
   227→			} else {
   228→				fmt.Printf("Removing sandbox %q...\n", sandbox.Name)
   229→				if err := client.DestroySandbox(sandbox.ID); err != nil {
   230→					fmt.Fprintf(os.Stderr, "Warning: failed to delete sandbox: %v\n", err)
   231→				} else {
   232→					fmt.Printf("Sandbox %q deleted.\n", sandbox.Name)
   233→				}
   234→			}
   235→		}
   236→
   237→		return sshErr
   238→	},
   239→}
