   402→				fmt.Println("No servers configured — run: sandcastle login <url>")
   403→				return nil
   404→			}
   405→
   406→			aliases := make([]string, 0, len(cfg.Servers))
   407→			for alias := range cfg.Servers {
   408→				aliases = append(aliases, alias)
   409→			}
   410→			sort.Strings(aliases)
   411→
   412→			for _, alias := range aliases {
   413→				srv := cfg.Servers[alias]
   414→				if alias == cfg.CurrentServer {
   415→					fmt.Printf("  \033[1m* %-16s\033[0m %s\n", alias, srv.URL)
   416→				} else {
   417→					fmt.Printf("    %-16s %s\n", alias, srv.URL)
   418→				}
   419→			}
   420→
   421→			return nil
   422→		}
