   427→		if _, ok := cfg.Servers[name]; ok {
   428→			cfg.CurrentServer = name
   429→			if err := config.Save(cfg); err != nil {
   430→				return err
   431→			}
   432→			fmt.Printf("Switched to server %s (%s)\n", name, cfg.Servers[name].URL)
   433→			return nil
   434→		}
   435→
   436→		// Try matching by URL
   437→		for alias, srv := range cfg.Servers {
   438→			if srv.URL == strings.TrimRight(name, "/") {
   439→				cfg.CurrentServer = alias
   440→				if err := config.Save(cfg); err != nil {
