   452→var setCmd = &cobra.Command{
   453→	Use:   "set <name> <temp|keep>",
   454→	Short: "Toggle sandbox between temporary and kept",
   455→	Long: `Toggle a sandbox between temporary (auto-remove on exit) and kept.
   456→
   457→  temp   Mark as temporary — will be removed when the CLI session exits
   458→  keep   Mark as kept — will not be auto-removed`,
   459→	Args: cobra.ExactArgs(2),
   460→	RunE: func(cmd *cobra.Command, args []string) error {
   461→		client, err := api.NewClient()
   462→		if err != nil {
   463→			return err
   464→		}
   465→		printServer(client)
   466→
   467→		sandbox, err := findSandboxByName(client, args[0])
   468→		if err != nil {
   469→			return err
   470→		}
   471→
   472→		mode := strings.ToLower(args[1])
   473→		var temp bool
   474→		switch mode {
   475→		case "temp":
   476→			temp = true
   477→		case "keep":
   478→			temp = false
   479→		default:
   480→			return fmt.Errorf("unknown mode %q: use \"temp\" or \"keep\"", args[1])
   481→		}
   482→
   483→		sandbox, err = client.UpdateSandbox(sandbox.ID, api.UpdateSandboxRequest{Temporary: &temp})
   484→		if err != nil {
   485→			return err
   486→		}
   487→
   488→		if temp {
   489→			fmt.Printf("Sandbox %q set to temporary (will be removed on exit).\n", sandbox.Name)
   490→		} else {
   491→			fmt.Printf("Sandbox %q set to keep (will not be removed on exit).\n", sandbox.Name)
   492→		}
   493→		return nil
   494→	},
   495→}
   496→
   497→func envTruthy(key string) bool {
   498→	v := strings.ToLower(os.Getenv(key))
   499→	return v == "1" || v == "true" || v == "yes"
   500→}
   501→
   502→func findSandboxByName(client *api.Client, name string) (*api.Sandbox, error) {
   503→	sandboxes, err := client.ListSandboxes()
   504→	if err != nil {
   505→		return nil, err
   506→	}
   507→	for _, s := range sandboxes {
   508→		if s.Name == name {
   509→			return &s, nil
   510→		}
   511→	}
   512→	return nil, fmt.Errorf("sandbox %q not found", name)
   513→}
