var useCmd = &cobra.Command{
	Use:   "use [name]",
	Short: "Show or set active server/sandbox",
	Long: `Without arguments, shows the current server and active sandbox.
With an argument, switches the active server or sandbox.

Examples:
  sandcastle use                  # Show current server and sandbox
  sandcastle use my-sandbox       # Set active sandbox
  sandcastle use prod             # Switch to server "prod" (if configured)`,
	Args: cobra.MaximumNArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		cfg, err := config.Load()
		if err != nil {
			return err
		}

		// No args: list all servers, highlight active
		if len(args) == 0 {
			if len(cfg.Servers) == 0 {
				fmt.Println("No servers configured — run: sandcastle login <url>")
				return nil
			}

			aliases := make([]string, 0, len(cfg.Servers))
			for alias := range cfg.Servers {
				aliases = append(aliases, alias)
			}
			sort.Strings(aliases)

			for _, alias := range aliases {
				srv := cfg.Servers[alias]
				if alias == cfg.CurrentServer {
					fmt.Printf("  \033[1m* %-16s\033[0m %s\n", alias, srv.URL)
				} else {
					fmt.Printf("    %-16s %s\n", alias, srv.URL)
				}
			}

			return nil
		}

		name := args[0]

		// Check if name matches a server alias or URL
		if _, ok := cfg.Servers[name]; ok {
			cfg.CurrentServer = name
			if err := config.Save(cfg); err != nil {
				return err
			}
			fmt.Printf("Switched to server %s (%s)\n", name, cfg.Servers[name].URL)
			return nil
		}

		// Try matching by URL
		for alias, srv := range cfg.Servers {
			if srv.URL == strings.TrimRight(name, "/") {
				cfg.CurrentServer = alias
				if err := config.Save(cfg); err != nil {
					return err
				}
				fmt.Printf("Switched to server %s (%s)\n", alias, srv.URL)
				return nil
			}
		}

		return fmt.Errorf("server %q not found — run: sandcastle use", name)
	},
}

var setCmd = &cobra.Command{
	Use:   "set <name> <temp|keep>",
	Short: "Toggle sandbox between temporary and kept",
	Long: `Toggle a sandbox between temporary (auto-remove on exit) and kept.

  temp   Mark as temporary — will be removed when the CLI session exits
  keep   Mark as kept — will not be auto-removed`,
	Args: cobra.ExactArgs(2),
	RunE: func(cmd *cobra.Command, args []string) error {
		client, err := api.NewClient()
		if err != nil {
			return err
		}
		printServer(client)

		sandbox, err := findSandboxByName(client, args[0])
		if err != nil {
			return err
		}

		mode := strings.ToLower(args[1])
		var temp bool
		switch mode {
		case "temp":
			temp = true
		case "keep":
			temp = false
		default:
			return fmt.Errorf("unknown mode %q: use \"temp\" or \"keep\"", args[1])
		}

		sandbox, err = client.UpdateSandbox(sandbox.ID, api.UpdateSandboxRequest{Temporary: &temp})
		if err != nil {
			return err
		}

		if temp {
			fmt.Printf("Sandbox %q set to temporary (will be removed on exit).\n", sandbox.Name)
		} else {
			fmt.Printf("Sandbox %q set to keep (will not be removed on exit).\n", sandbox.Name)
		}
		return nil
	},
}

func envTruthy(key string) bool {
	v := strings.ToLower(os.Getenv(key))
	return v == "1" || v == "true" || v == "yes"
}

func findSandboxByName(client *api.Client, name string) (*api.Sandbox, error) {
	sandboxes, err := client.ListSandboxes()
	if err != nil {
		return nil, err
	}
	for _, s := range sandboxes {
		if s.Name == name {
			return &s, nil
		}
	}
	return nil, fmt.Errorf("sandbox %q not found", name)
}

package cmd

import (
	"fmt"
	"os"
	"text/tabwriter"
	"time"

	"github.com/sandcastle/cli/api"
	"github.com/spf13/cobra"
)

var tsAuthKey string

func init() {
	rootCmd.AddCommand(tailscaleCmd)
	tailscaleCmd.AddCommand(tsEnableCmd)
	tailscaleCmd.AddCommand(tsDisableCmd)
	tailscaleCmd.AddCommand(tsStatusCmd)
	tailscaleCmd.AddCommand(tsConnectCmd)
	tailscaleCmd.AddCommand(tsDisconnectCmd)

	tsEnableCmd.Flags().StringVar(&tsAuthKey, "auth-key", "", "Tailscale auth key (tskey-auth-...) — skips interactive login")
}

var tailscaleCmd = &cobra.Command{
	Use:     "tailscale",
	Aliases: []string{"ts"},
	Short:   "Manage Tailscale connectivity",
}

var tsEnableCmd = &cobra.Command{
	Use:   "enable",
	Short: "Enable Tailscale sidecar (interactive login or --auth-key)",
	RunE: func(cmd *cobra.Command, args []string) error {
		client, err := api.NewClient()
		if err != nil {
			return err
		}
		printServer(client)

		// If auth key provided, use the legacy one-shot flow
		if tsAuthKey != "" {
			if err := client.TailscaleEnable(tsAuthKey); err != nil {
				return err
			}
			fmt.Println("Tailscale enabled. Approve subnet routes in the Tailscale admin console.")
			return nil
		}

		// Interactive login flow
		fmt.Println("Starting Tailscale sidecar...")
		resp, err := client.TailscaleLogin()
		if err != nil {
			return err
		}

		fmt.Println()
		fmt.Println("To authenticate, open this URL in your browser:")
		fmt.Println()
		fmt.Printf("    %s\n", resp.LoginURL)
		fmt.Println()
		fmt.Print("Waiting for login...")

		for {
			time.Sleep(3 * time.Second)
			status, err := client.TailscaleLoginStatus()
			if err != nil {
				fmt.Println()
				return fmt.Errorf("checking login status: %w", err)
			}

			switch status.Status {
			case "authenticated":
				fmt.Println(" done!")
				fmt.Println()
				fmt.Printf("Tailscale IP:  %s\n", status.TailscaleIP)
				fmt.Printf("Hostname:      %s\n", status.Hostname)
				fmt.Printf("Tailnet:       %s\n", status.Tailnet)
				fmt.Println()
				fmt.Println("Approve subnet routes in the Tailscale admin console.")
				return nil
			case "error":
				fmt.Println()
				return fmt.Errorf("login failed: %s", status.Error)
			default:
				fmt.Print(".")
			}
		}
	},
}

var tsDisableCmd = &cobra.Command{
	Use:   "disable",
	Short: "Disable Tailscale sidecar",
	RunE: func(cmd *cobra.Command, args []string) error {
		client, err := api.NewClient()
		if err != nil {
			return err
		}
		printServer(client)

		if err := client.TailscaleDisable(); err != nil {
			return err
		}

		fmt.Println("Tailscale disabled.")
		return nil
	},
}

var tsStatusCmd = &cobra.Command{
	Use:   "status",
	Short: "Show Tailscale status",
	RunE: func(cmd *cobra.Command, args []string) error {
		client, err := api.NewClient()
		if err != nil {
			return err
		}
		printServer(client)

		status, err := client.TailscaleStatus()
		if err != nil {
			return err
		}

		state := "offline"
		if status.Running && status.Online {
			state = "online"
		} else if status.Running {
			state = "running"
		}

		w := tabwriter.NewWriter(os.Stdout, 0, 0, 2, ' ', 0)
		fmt.Fprintf(w, "State:\t%s\n", state)
		fmt.Fprintf(w, "Tailscale IP:\t%s\n", valueOrDash(status.TailscaleIP))
		fmt.Fprintf(w, "Hostname:\t%s\n", valueOrDash(status.Hostname))
		fmt.Fprintf(w, "Tailnet:\t%s\n", valueOrDash(status.Tailnet))
		fmt.Fprintf(w, "Network:\t%s\n", valueOrDash(status.Network))
		fmt.Fprintf(w, "Container:\t%s\n", valueOrDash(status.ContainerID))
		fmt.Fprintf(w, "Connected sandboxes:\t%d\n", status.ConnectedSandboxes)
		w.Flush()

		if len(status.Sandboxes) > 0 {
			fmt.Println()
			w = tabwriter.NewWriter(os.Stdout, 0, 0, 2, ' ', 0)
			fmt.Fprintln(w, "SANDBOX\tBRIDGE IP\tSSH COMMAND")
			for _, sb := range status.Sandboxes {
				sshCmd := "—"
				if sb.IP != "" {
					sshCmd = fmt.Sprintf("ssh %s", sb.IP)
				}
				fmt.Fprintf(w, "%s\t%s\t%s\n", sb.Name, valueOrDash(sb.IP), sshCmd)
			}
			w.Flush()
		}

		return nil
	},
}

var tsConnectCmd = &cobra.Command{
	Use:   "connect <sandbox>",
	Short: "Connect a sandbox to Tailscale network",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		client, err := api.NewClient()
		if err != nil {
			return err
		}
		printServer(client)

		sandbox, err := findSandboxByName(client, args[0])
		if err != nil {
			return err
		}

		sandbox, err = client.TailscaleConnect(sandbox.ID)
		if err != nil {
			return err
		}

		fmt.Printf("Sandbox %q connected to Tailscale.\n", sandbox.Name)
		fmt.Println("Run `sandcastle ts status` to see the bridge IP.")
		return nil
	},
}

var tsDisconnectCmd = &cobra.Command{
	Use:   "disconnect <sandbox>",
	Short: "Disconnect a sandbox from Tailscale network",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		client, err := api.NewClient()
		if err != nil {
			return err
		}
		printServer(client)

		sandbox, err := findSandboxByName(client, args[0])
		if err != nil {
			return err
		}

		sandbox, err = client.TailscaleDisconnect(sandbox.ID)
		if err != nil {
			return err
		}

		fmt.Printf("Sandbox %q disconnected from Tailscale.\n", sandbox.Name)
		return nil
	},
}

func valueOrDash(s string) string {
	if s == "" {
		return "—"
	}
	return s
}

